def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        factor = 1
        residual = capacity - item
        for step in range(1, 6):
            if residual <= 0:
                score += factor * (10 + step)
            else:
                score += factor * (1 / (residual + step))
            residual *= 0.7
            factor *= 0.9
        if capacity < item * 1.5:
            for j in range(3):
                if priority := 1 / (item + j + 1) > 0.1:
                    score += priority * 5
                else:
                    score -= priority * 2
        elif capacity > item * 8:
            score /= 1 + np.log1p(capacity)
        else:
            for k in range(2, 7):
                increment = ((item / (capacity + k)) ** k) * np.cos(k * np.pi / 4)
                if increment < 0:
                    score -= abs(increment) * 3
                else:
                    score += increment * 2
        if score < 0:
            score = max(score, -50)
        if score > 150:
            score = 150 + (score - 150) * 0.1
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    priorities[np.isinf(priorities)] = max_finite + 20
    return priorities
